#include <vector>
#include <string>
using namespace std;

class Solution {
public:
    bool isIsomorphic(string s, string t) {
        if (s.length() != t.length()) return false;

        vector<int> mapS(256, -1), mapT(256, -1);

        for (int i = 0; i < s.length(); i++) {
            if (mapS[s[i]] == -1 && mapT[t[i]] == -1) {
                mapS[s[i]] = t[i];
                mapT[t[i]] = s[i];
            } else if (mapS[s[i]] != t[i] || mapT[t[i]] != s[i]) {
                return false;
            }
        }
        return true;
    }
};

